SELECT AVG(accuracy) AS average_accuracy
FROM model_performance
WHERE id_model = 1;

SELECT m.model_name, mp.accuracy, mp.precision, mp.recall, mp.f1_score
FROM models m
LEFT JOIN model_performance mp ON m.id_model = mp.id_model;

SELECT AVG(accuracy) AS average_accuracy
FROM model_performance
WHERE created_at >= datetime('now', '-7 days');
